const [consentGiven, setConsentGiven] = useState(false);

// Block WebSocket until consent
useEffect(() => {
  if (consentGiven) connectWebSocket();
}, [consentGiven]);

if (!consentGiven) return <ConsentBanner onAccept={() => setConsentGiven(true)} />;

